let para=document.getElementsByClassName("body")[0].children[0].children;let latex="\\documentclass[10pt]{article}\n\\usepackage[a4paper, margin=1cm]{geometry}\n\\usepackage{relsize}\n\\usepackage{fp}\n\\usepackage{adjustbox}\n\n\\begin{document}\n\\begin{center}";let scaleFactor="0.65";for(let i=0;i<para.length;i++){if(para[i].tagName=="P"&&para[i].innerText!=""){latex+="\\scalebox{"+scaleFactor+"}{\n\\parbox{\\fpeval{\\textwidth/"+scaleFactor+"}}{\n";latex+=para[i].innerText;latex+="\n}\n}\n"}if(para[i].tagName=="H1"||para[i].tagName=="H2"&&para[i].innerText!=""){latex+="\\scalebox{"+scaleFactor+"}{\n\\parbox{\\fpeval{\\textwidth/"+scaleFactor+"}}{\n\\textbf{";latex+=para[i].innerText;latex+="}\n}\n}\n"}}latex+="\\end{center}\n\\end{document}";const storage=document.createElement("div");document.body.append(storage);storage.innerText=latex;var range=document.createRange();range.selectNode(storage);window.getSelection().removeAllRanges();window.getSelection().addRange(range);document.execCommand("copy");window.getSelection().removeAllRanges();storage.remove();alert("Copied latex!");
